public int countVowelStrings(int n) {
    int[] dp = {1, 1, 1, 1, 1};
    for (int i = 2; i <= n; i++) {
        for (int j = 3; j >= 0; j--) {
            dp[j] = dp[j] + dp[j + 1];
        }
    }
    return Arrays.stream(dp).sum();
}
